# generate Michelangelo python client
# The client generated by this script is a wrapper of the gRPC client code generated
# by the gRPC compiler, which manages the gRPC channel and set the necessary headers.
import importlib
import os
import sys
import jinja2
from template import INIT_TEMPLATE, SERVICE_TEMPLATE


env = jinja2.Environment()
init_template = env.from_string(INIT_TEMPLATE)
service_template = env.from_string(SERVICE_TEMPLATE)
current_dir = os.path.dirname(os.path.realpath(__file__))
# pbgen_dir contains the python code generated by gRPC compiler
pbgen_dir = os.path.join(current_dir, '../../michelangelo/gen/api/v2')
# the destination directory for the generated client code
gen_dir = os.path.join(current_dir, '../../michelangelo/api/v2/services/gen')
sys.path.insert(0, os.path.join(current_dir, '../../michelangelo'))


def get_crds():
    files = os.listdir(pbgen_dir)
    crds = []

    for f in files:
        if f.endswith('_svc_pb2_grpc.py'):
            snake_name = f.replace('_svc_pb2_grpc.py', '')
            if os.path.exists(os.path.join(pbgen_dir, snake_name + '_pb2.py')):
                module = importlib.import_module('michelangelo.gen.api.v2.{}_pb2'.format(snake_name))
                cls = getattr(module, to_camel_case(snake_name), None)
                if cls:
                    # check if the class is a crd type
                    option_fields = cls.DESCRIPTOR.GetOptions().ListFields()
                    for field in option_fields:
                        if field[0].full_name == 'michelangelo.api.resource':
                            crds.append({
                                'group_name': 'v2',
                                'crd_name': snake_name.replace('_', ' '),
                                'crd_snake': snake_name,
                                'crd_camel': to_camel_case(snake_name)
                            })
    return sorted(crds, key=lambda x: x['crd_snake'])


def to_camel_case(snake_case):
    splits = snake_case.split('_')
    return ''.join([s.title() for s in splits])


def gen_service(crd):
    content = service_template.render(**crd)
    with open(os.path.join(gen_dir, crd['crd_snake'] + '.py'), 'w+') as f:
        f.write(content)


def gen_init(crds):
    with open(os.path.join(gen_dir, '__init__.py'), 'w+') as f:
        f.write(init_template.render(crds=crds))


def run():
    crds = get_crds()
    os.system('rm -rf {}/*'.format(gen_dir))
    for crd in crds:
        gen_service(crd)
    gen_init(crds)


if __name__ == '__main__':
    run()
